#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    int min_price = INT_MAX;
    int max_profit = 0;

    for (int i = 0; i < N; ++i) {
        int price;
        cin >> price;
        if (price < min_price) {
            min_price = price;
        }
        int profit = price - min_price;
        if (profit > max_profit) {
            max_profit = profit;
        }
    }

    cout << max_profit << '\n';

    return 0;
}
